import React from 'react';
import { Link } from 'react-router-dom';

const HomePage = ({ user }) => (
  <div>
    <h1>Golf Charity Subscription Platform</h1>
    <p>Join, track your golf scores, support charity, and win monthly prizes.</p>
    <ul>
      <li>Monthly / Yearly plans (Stripe)</li>
      <li>Score entry (latest 5 scores, Stableford 1-45)</li>
      <li>Monthly draw with 3/4/5 number matches</li>
      <li>Charity contribution at least 10%</li>
    </ul>
    {!user ? <Link to="/register"><button>Get Started</button></Link> : <Link to='/dashboard'><button>Go to Dashboard</button></Link>}
  </div>
);

export default HomePage;
